#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    for (int i = 0; i < T; ++i) {
        int match = 1;
        for (int j = 0; j < T; ++j) {
            char s[5];
            scanf("%4s", s);
            int isYes = (strcmp(s, "YES") == 0);
            if ((j == i) != isYes) {
                match = 0;
                // consume remaining lines of this test case
                for (int k = j + 1; k < T; ++k) {
                    scanf("%4s", s);
                }
                break;
            }
        }
        printf("%s\n", match ? "YES" : "NO");
    }
    return 0;
}

