const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let pos = 0;
if (input.length === 0) process.exit(0);
const T = parseInt(input[pos++], 10);
let results = [];
for (let i = 0; i < T; ++i) {
    let match = true;
    for (let j = 0; j < T; ++j) {
        const s = input[pos++];
        const isYes = s === 'YES';
        if ((j === i) !== isYes) {
            match = false;
            // skip remaining strings of this test case
            pos += T - j - 1;
            break;
        }
    }
    results.push(match ? 'YES' : 'NO');
}
console.log(results.join('\n'));

